mapper.select:
SELECT ECCF.BUYER_CD , ECCF.FORM_NUM , GETCOMPANYNAME(ECCF.GATE_CD, ECCF.BUYER_CD, #{ses.langCd}) AS BUYER_NM , ECCF.FORM_TYPE , ECCF.CONT_TYPE , ECCF.FORM_NM , ECCF.CONT_DIV , ECCF.BUNDLE_FLAG , ECCF.AUTO_RENEW_FLAG , ECCF.NH_COMM_FLAG , ECCF.USE_FLAG , ECCF.SIGN_STATUS , (ECCF.REG_DATE , 'YYYYMMDD') AS REG_DATE , ECCF.FORM_FILE_NM , (SELECT COUNT(*) FROM STOCECRL RL JOIN STOCECCT CT -- 전자계약서 ON (RL.GATE_CD = CT.GATE_CD AND RL.BUYER_CD = CT.BUYER_CD AND RL.CONT_NUM = CT.CONT_NUM AND RL.CONT_CNT = CT.CONT_CNT AND CT.DEL_FLAG = '0') WHERE RL.GATE_CD = ECCF.GATE_CD AND RL.FORM_NUM = ECCF.FORM_NUM AND RL.DEL_FLAG = '0') + (SELECT COUNT(*) FROM STOCLEGL -- 정도경영 및 보안서약서 WHERE GATE_CD = ECCF.GATE_CD AND FORM_NUM = ECCF.FORM_NUM AND DEL_FLAG = '0') AS FORM_USE_CNT -- 해당 폼 사용횟수 FROM STOCECCF ECCF LEFT OUTER JOIN STOCCUST CUST ON (CUST.GATE_CD = ECCF.GATE_CD AND CUST.CUST_CD = ECCF.BUYER_CD AND CUST.DEL_FLAG = '0') WHERE ECCF.GATE_CD = #{ses.gateCd}
AND ECCF.BUYER_CD = #{BUYER_CD}
AND UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{BUYER_NM}) '%'
AND UPPER(ECCF.FORM_NM) LIKE '%' UPPER(#{FORM_NM}) '%'
AND ECCF.SIGN_STATUS = #{SIGN_STATUS}
AND ECCF.REG_DATE >= (#{REG_FROM_DATE})
AND ECCF.REG_DATE <= (#{REG_TO_DATE})
AND ECCF.FORM_TYPE = #{FORM_TYPE}
AND ECCF.CONT_TYPE = #{CONT_TYPE}
AND ECCF.CONT_DIV = #{CONT_DIV}
AND ECCF.BUNDLE_FLAG = #{BUNDLE_FLAG}
AND ECCF.AUTO_RENEW_FLAG = #{AUTO_RENEW_FLAG}
AND ECCF.USE_FLAG = #{USE_FLAG}
AND ECCF.DEL_FLAG = '0' ORDER BY ECCF.BUYER_CD, ECCF.FORM_TYPE, ECCF.CONT_TYPE, ECCF.FORM_NM

mapper.update:
UPDATE STOCECCF
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
     , USE_FLAG = #{USE_FLAG}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND FORM_NUM = #{FORM_NUM}

UPDATE STOCECCF
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
     , DEL_FLAG = '1'
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND FORM_NUM = #{FORM_NUM}

UPDATE STOCECCR
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
	 , DEL_FLAG    = '1'
WHERE GATE_CD  = #{ses.gateCd}
  AND FORM_NUM = #{FORM_NUM}

mapper.select:
SELECT ECCF.BUYER_CD
	 , ECCF.FORM_NUM
	 , ECCF.FORM_TYPE
	 , ECCF.CONT_TYPE
	 , ECCF.CONT_DIV
	 , ECCF.FORM_NM
	 , ECCF.BUNDLE_FLAG
	 , ECCF.AUTO_RENEW_FLAG
	 , ECCF.NH_COMM_FLAG
	 , ECCF.RMK
	 , ECCF.SUB_FORM_DIV
	 , ECCF.ATT_FILE_NUM
	 , ECCF.USE_FLAG
	 , ECCF.APP_DOC_NUM
	 , ECCF.APP_DOC_CNT
	 , ECCF.SIGN_STATUS
	 , CUST.CUST_NM AS BUYER_NM
     , ECCF.FORM_FILE_NM
     , (SELECT RELAT_YN FROM STOCCUST WHERE GATE_CD = #{ses.gateCd} AND CUST_CD = #{BUYER_CD}) AS RELAT_YN
  FROM STOCECCF ECCF
  LEFT OUTER JOIN STOCECCR ECCR
   ON (ECCF.GATE_CD  = ECCR.GATE_CD
   AND ECCF.FORM_NUM = ECCR.REL_FORM_NUM
   AND ECCR.FORM_NUM = (SELECT FORM_NUM
   						  FROM STOCECCF
   						 WHERE GATE_CD = #{ses.gateCd}

							  AND BUYER_CD = #{BUYER_CD} 
							 AND BUYER_CD = #{BUYER_CD} 



								AND FORM_NUM = #{FORM_NUM}



									AND APP_DOC_NUM = #{APP_DOC_NUM}
									AND APP_DOC_CNT = #{APP_DOC_CNT}



   						)
   AND ECCR.DEL_FLAG = '0')
  LEFT OUTER JOIN STOCCUST CUST
	   ON (CUST.GATE_CD = ECCF.GATE_CD
	  AND  CUST.CUST_CD = ECCF.BUYER_CD)
 WHERE ECCF.GATE_CD  = #{ses.gateCd}

	  AND ECCF.BUYER_CD = #{BUYER_CD} 
	 AND ECCF.BUYER_CD = #{BUYER_CD} 



		AND ECCF.FORM_NUM = #{FORM_NUM}



			AND ECCF.APP_DOC_NUM = #{APP_DOC_NUM}
			AND ECCF.APP_DOC_CNT = #{APP_DOC_CNT}



   AND ECCF.DEL_FLAG = '0'

SELECT (CASE WHEN ECCR.FORM_NUM IS NULL THEN 0 ELSE 1 END) AS SELECTED , ECCF.BUYER_CD , ECCF.FORM_NUM AS REL_FORM_NUM , ECCF.FORM_TYPE , ECCF.FORM_NM , ECCR.FORM_NUM , row_number() over( order by ECCF.FORM_NM DESC) AS NUM , ECCR.REQUIRE_FLAG , ECCR.REL_FORM_SQ FROM STOCECCF ECCF LEFT OUTER JOIN STOCECCR ECCR ON (ECCF.GATE_CD = ECCR.GATE_CD
AND (ECCF.BUYER_CD = ECCR.BUYER_CD OR ECCF.NH_COMM_FLAG = '1')
AND ECCF.BUYER_CD = ECCR.BUYER_CD
AND ECCF.FORM_NUM = ECCR.REL_FORM_NUM AND ECCR.FORM_NUM = #{FORM_NUM} AND ECCR.DEL_FLAG = '0') WHERE ECCF.GATE_CD = #{ses.gateCd}
AND (ECCF.BUYER_CD = #{BUYER_CD} OR ECCF.NH_COMM_FLAG = '1')
AND ECCF.BUYER_CD = #{BUYER_CD}
AND ECCF.FORM_TYPE = '200' --부서식만
AND ECCF.FORM_NUM != #{FORM_NUM}
AND ECCF.DEL_FLAG = '0' AND ECCF.SIGN_STATUS = 'E' -- 결재완료 AND ECCF.USE_FLAG = '1' -- 사용중 ORDER BY ECCR.REL_FORM_SQ, ECCR.FORM_NUM, ECCF.FORM_NUM

