	 , CONT_DIV
	 , FORM_NM
	 , BUNDLE_FLAG
	 , AUTO_RENEW_FLAG
	 , NH_COMM_FLAG
	 , RMK
	 , SUB_FORM_DIV
	 , ATT_FILE_NUM
	 , USE_FLAG
	 , SIGN_STATUS
	 , FORM_FILE_NM
) VALUES (
	   #{ses.gateCd}
	 , #{BUYER_CD}
	 , #{FORM_NUM}
	 , SYSDATE
	 , #{ses.userId}
	 , SYSDATE
	 , #{ses.userId}
	 , '0'
	 , #{FORM_TYPE}
	 , #{CONT_TYPE}
	 , #{CONT_DIV}
	 , #{FORM_NM}
	 , #{BUNDLE_FLAG}
	 , #{AUTO_RENEW_FLAG}
	 , (#{NH_COMM_FLAG}, '0')
	 , #{RMK}
	 , #{SUB_FORM_DIV}
	 , #{ATT_FILE_NUM}
	 , #{USE_FLAG}
	 , 'T'
	 , #{FORM_FILE_NM}
)

